UPDATE chat_room_read   /*kr.or.ddit.common.webSocket.chat.mapper.IChatMapper.updateLastRead*/
SET last_read_msg_no = #{chatMsgNo}
WHERE chat_room_no = #{chatRoomNo}
  AND chat_member_id = #{chatMemberId}

UPDATE CHAT_ROOM_MEMBER /*kr.or.ddit.common.webSocket.chat.mapper.IChatMapper.leaveRoom*/
SET LEFT_DTTM = SYSDATE
WHERE CHAT_ROOM_NO = #{chatRoomNo}
  AND USER_NO = #{userNo}
  AND LEFT_DTTM IS NULL

UPDATE CHAT_ROOM_READ   /*kr.or.ddit.common.webSocket.chat.mapper.IChatMapper.readAllMessages*/
SET LAST_READ_MSG_NO = (
    SELECT MAX(CHAT_MSG_NO)
    FROM CHAT_MESSAGE
    WHERE CHAT_ROOM_NO = #{chatRoomNo}
)
WHERE CHAT_ROOM_NO = #{chatRoomNo}
  AND CHAT_MEMBER_ID = #{chatMemberId}

