SELECT  CHAT_MEMBER_ID  /*kr.or.ddit.common.webSocket.chat.vo.ChatMessageVO.selectMemberId*/
FROM    CHAT_ROOM_MEMBER
WHERE   CHAT_ROOM_NO = #{chatRoomNo}
  AND   USER_NO = #{userNo}
  AND   LEFT_DTTM IS NULL

SELECT COUNT(*) /*kr.or.ddit.common.webSocket.chat.mapper.IChatMapper.isRoomMember*/
FROM CHAT_ROOM_MEMBER
WHERE CHAT_ROOM_NO = #{chatRoomNo}
  AND USER_NO = #{userNo}
  AND LEFT_DTTM IS NULL

SELECT *
FROM CHAT_ROOM
WHERE CHAT_JOIN_KEY = #{joinKey}
  AND APT_CMPLEX_NO = #{aptCmplexNo}
  AND USE_YN = 'Y'

