    chat_room_no
  , chat_room_nm
  , chat_room_ty_cd
  , reg_dt
  , use_yn
  , rgtr_id
  , chat_join_key
  , apt_cmplex_no
  , chat_room_desc
)VALUES (
    #{chatRoomNo}
